;-------------------------------------------------------------------------------
*event_1
;[exp] true

@addevent name=イーラ教団 num=0
@shop name=イーラ教団
@walk turn=w move=w
[texton]
[ブラザー]「Come back again, heh heh heh.」[k]
[textoff]

[eventoff]
;-------------------------------------------------------------------------------
*event_2
;[exp] true

@enterhouse img=interior_02
[texton]
[name n="Desert Person"]「Far to the south, beyond the vast desert, there is said to be a forgotten town.」[k]
[name n="Desert Person"]「...But don't go any further from here. No one who has gone there has ever come back.」[k]
[name n="Desert Person"]「Those who set foot in the desert ahead will wander aimlessly and perish.」[k]
[name n="Desert Person"]「With shifting sands everywhere and violent sandstorms, it's easy to lose your sense of direction. I'm not trying to be negative, but if you don't want to die, you'd better turn back.」[k]
[textoff]
@exithouse

[eventoff]
;-------------------------------------------------------------------------------
*event_3
;[exp] true

@enterhouse img=interior_02
[texton]
[name n="Desert Person" f=archer_purple_01]「Let me tell you something useful. In places with strong winds, it's a good idea to use movable rocks as windbreaks!」[k]
[textoff]
@exithouse

[eventoff]
;-------------------------------------------------------------------------------
*event_4
;[exp] onObjectTrigger

@barrel noguest
@damage v=&'game.curTarget.addParam("magic", 9)'
@notice text=&'"<p>" + game.curTarget.displayName + "<w> had MP restored!"'

[eventoff]
;-------------------------------------------------------------------------------
*event_5
;[exp] inSearching

@delevent
@getitem item=師範の腕輪

[eventoff]
